UPDATE	s_home_manager
SET		HM_USE_YN	=	'D'
WHERE	HM_KEYNO	=	#{HM_KEYNO}

UPDATE	s_menu_manager
SET		MN_DEL_YN		=	'Y'
	  , MN_DELDT		=	NOW()
	  , MN_MODNM		=	#{MN_MODNM} 
WHERE	MN_HOMEDIV_C	=	#{MN_KEYNO}

